defmodule MyApp.PhoenixEndpoint do
  use Phoenix.Controller

  alias SweetXml.XPath

  def parse_xml(conn) do
    {:ok, body} = Plug.Conn.read_body(conn)
    xml = String.trim(body)

    xpath = "//xmlns:Envelope/xmlns:Body"
    %{nodes: nodes} = XPath.search(xml, xpath)

    Enum.map(nodes, fn node ->
      {:ok, value} = SweetXml.parse_document(node)
      value
    end)
  end
end